import{_ as a,o as i,c as s,a2 as r}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Servicios","description":"","frontmatter":{},"headers":[],"relativePath":"es/api/services.md","filePath":"es/api/services.md"}'),o={name:"es/api/services.md"};function n(c,e,l,t,d,p){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="servicios" tabindex="-1">Servicios <a class="header-anchor" href="#servicios" aria-label="Permalink to &quot;Servicios&quot;">​</a></h1><p>Todos los servicios de Clearance viven en <code>src/Services/</code> y se resuelven desde el contenedor, p. ej. <code>app(ContextService::class)</code>. Son la capa a la que recurrir desde controladores, políticas, y jobs — en cualquier lugar donde el modelo <code>User</code> pueda no usar el trait <code>HasClearance</code>.</p><h2 id="contextservice" tabindex="-1"><code>ContextService</code> <a class="header-anchor" href="#contextservice" aria-label="Permalink to &quot;`ContextService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\ContextService</code> (<code>src/Services/ContextService.php</code>) es el motor detrás de la autorización contextual. El <a href="/clearance-docs/es/api/facade.html">facade <code>Clearance</code></a> y el trait <code>HasClearance</code> delegan ambos en él.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\ContextService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ContextService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">canIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasPermissionIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// alias</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasRoleIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveFor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Collection of all effective permission names</span></span></code></pre></div><p><code>resolveFor()</code> construye su resultado usando una precedencia de 3 fuentes:</p><ol><li>Concesiones de rol contextual</li><li>Concesiones de rol global</li><li>Overrides por contexto (<code>forced_on</code> añade, <code>forced_off</code> siempre gana)</li></ol><p>Consulta <a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a> para el recorrido conceptual de esta precedencia.</p><h2 id="roleservice" tabindex="-1"><code>RoleService</code> <a class="header-anchor" href="#roleservice" aria-label="Permalink to &quot;`RoleService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\RoleService</code> (<code>src/Services/RoleService.php</code>) gestiona los roles techo.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\RoleService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole, $parentRole);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">removeParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Método</th><th>Descripción</th></tr></thead><tbody><tr><td><code>setParent($childRole, $parentRole)</code></td><td>Establece un techo: los permisos excedentes en <code>$childRole</code> más allá del conjunto del padre se recortan silenciosamente. Lanza <code>ClearanceScopeViolationException</code> si el hijo ya es un padre, o el padre ya es un hijo.</td></tr><tr><td><code>removeParent($childRole)</code></td><td>Elimina la relación de techo.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Un techo solo recorta — nunca concede. Un rol padre permisivo no otorga, por sí mismo, ningún permiso al hijo. Eliminar un permiso de un rol padre propaga esa eliminación a cada rol hijo automáticamente.</p></div><p>Consulta <a href="/clearance-docs/es/features/roles.html">Roles</a> para el concepto de rol techo en más profundidad.</p><h2 id="permissionservice" tabindex="-1"><code>PermissionService</code> <a class="header-anchor" href="#permissionservice" aria-label="Permalink to &quot;`PermissionService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\PermissionService</code> (<code>src/Services/PermissionService.php</code>) respalda el CRUD del panel de Permisos.</p><p>Aplica la convención de nomenclatura <code>group-action</code>, controlada por las claves de configuración <code>enforce_naming_convention</code> y <code>naming_separator</code>, y protege el namespace de permisos <code>clearance-*</code> frente a ser creado, renombrado, o eliminado fuera del flujo de instalación.</p><h2 id="guardservice" tabindex="-1"><code>GuardService</code> <a class="header-anchor" href="#guardservice" aria-label="Permalink to &quot;`GuardService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\GuardService</code> (<code>src/Services/GuardService.php</code>) respalda el CRUD del panel de Guards.</p><p>Inyecta guards respaldados por BD en <code>auth.guards</code> al arrancar, filtrados por la clave de configuración <code>allowed_guard_drivers</code> — un driver no listado se omite con una advertencia en el log en lugar de corromper la configuración de auth.</p><h2 id="metaservice" tabindex="-1"><code>MetaService</code> <a class="header-anchor" href="#metaservice" aria-label="Permalink to &quot;`MetaService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\MetaService</code> (<code>src/Services/MetaService.php</code>) lee y escribe <code>clr_meta</code> (nombre de visualización, descripción, icono SVG sanitizado, color) para un sujeto de rol o guard. Respalda el editor de metadatos de visualización del panel de Configuración.</p><p>Los iconos SVG pasan por <code>Rivalex\\Clearance\\Support\\SvgSanitizer</code> (un sanitizador basado en lista de permitidos) tanto antes de almacenarse como al renderizarse.</p><h2 id="userclearanceservice" tabindex="-1"><code>UserClearanceService</code> <a class="header-anchor" href="#userclearanceservice" aria-label="Permalink to &quot;`UserClearanceService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\UserClearanceService</code> (<code>src/Services/UserClearanceService.php</code>) respalda el panel del módulo de Usuarios:</p><ul><li>Asignación de rol global</li><li>Asignación de rol contextual (vía <code>UserRoleContext</code>)</li><li>Overrides de permiso por contexto (vía <code>UserContextPermissionOverride</code>, <code>forced_on</code> / <code>forced_off</code>)</li><li>Eliminación de asignaciones, que propaga la eliminación de overrides</li></ul><p>Aplica un techo de privilegio: un actor que no sea <code>super_admin</code> no puede modificar sus propias asignaciones, ni puede otorgar un permiso que él mismo no posea. Consulta <a href="/clearance-docs/es/features/super-admin.html">Super Admin</a> y <a href="/clearance-docs/es/features/users.html">Usuarios</a>.</p><h2 id="excepciones" tabindex="-1">Excepciones <a class="header-anchor" href="#excepciones" aria-label="Permalink to &quot;Excepciones&quot;">​</a></h2><p>Todas en <code>src/Exceptions/</code>:</p><table tabindex="0"><thead><tr><th>Excepción</th><th>Se lanza cuando</th></tr></thead><tbody><tr><td><code>ClearanceConfigException</code></td><td>Se lee un valor inválido o mal configurado de <code>config/clearance.php</code> (p. ej. un <code>naming_separator</code> incorrecto).</td></tr><tr><td><code>ClearanceNamingException</code></td><td>Un nombre de permiso viola la convención de nomenclatura <code>group-action</code> mientras la aplicación de la regla está activada.</td></tr><tr><td><code>ClearanceProtectedResourceException</code></td><td>Se intenta modificar un permiso <code>clearance-*</code> protegido, o un recurso bloqueado, fuera del flujo de instalación.</td></tr><tr><td><code>ClearanceScopeViolationException</code></td><td>Una relación de rol techo inválida (un padre intentando convertirse en hijo, o viceversa), o un desajuste de alcance.</td></tr></tbody></table><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/api/facade.html">Facade</a> — el envoltorio de llamada estática alrededor de <code>ContextService</code>.</li><li><a href="/clearance-docs/es/api/traits-directives.html">Traits y Directivas</a> — los equivalentes de método de instancia y directiva Blade.</li><li><a href="/clearance-docs/es/api/artisan-commands.html">Comandos Artisan</a> — <code>clearance:install</code> y <code>clearance:backfill</code>, que siembran los datos sobre los que operan estos servicios.</li></ul>',32)])])}const u=a(o,[["render",n]]);export{k as __pageData,u as default};
